#include "llvm/ADT/APInt.h"
#include "llvm/ADT/PostOrderIterator.h" // For ReversePostOrderTraversal.
#include "llvm/ADT/STLExtras.h"         // For make_early_inc_range.
#include "llvm/IR/BasicBlock.h"
#include "llvm/IR/CFG.h"       // To instantiate RPOTraversal.
#include "llvm/IR/Constants.h" // For ConstantInt.
#include "llvm/IR/Function.h"
#include "llvm/IR/InstrTypes.h" // For BinaryOperator, etc.
#include "llvm/IR/Instruction.h"
#include "llvm/IR/Instructions.h"
#include "llvm/IR/LLVMContext.h"
#include "llvm/IR/Module.h"
#include "llvm/Support/Debug.h" // For errs().

#include <optional>
using namespace llvm;

// Takes \p Foo and apply a simple constant propagation optimization.
// \returns true if \p Foo was modified (i.e., something had been constant
// propagated), false otherwise.
bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = false;

  for (BasicBlock &BB : Foo) {
    for (Instruction &I : make_early_inc_range(BB)) {
      auto *BO = dyn_cast<BinaryOperator>(&I);
      if (!BO)
        continue;

      // Only fold integer-typed binary operators.
      if (!BO->getType()->isIntegerTy())
        continue;

      // Restrict to the opcodes we are asked to support.
      switch (BO->getOpcode()) {
      case Instruction::Add:
      case Instruction::Sub:
      case Instruction::Mul:
      case Instruction::SDiv:
      case Instruction::UDiv:
      case Instruction::Shl:
      case Instruction::LShr:
      case Instruction::AShr:
      case Instruction::And:
      case Instruction::Or:
      case Instruction::Xor:
        break;
      default:
        continue;
      }

      auto *LHS = dyn_cast<ConstantInt>(BO->getOperand(0));
      auto *RHS = dyn_cast<ConstantInt>(BO->getOperand(1));
      if (!LHS || !RHS)
        continue;

      const APInt &L = LHS->getValue();
      const APInt &R = RHS->getValue();
      const unsigned BW = L.getBitWidth();
      std::optional<APInt> Result;

      switch (BO->getOpcode()) {
      case Instruction::Add:
        Result = L + R;
        break;
      case Instruction::Sub:
        Result = L - R;
        break;
      case Instruction::Mul:
        Result = L * R;
        break;
      case Instruction::SDiv:
        if (!R.isZero())
          Result = L.sdiv(R);
        break;
      case Instruction::UDiv:
        if (!R.isZero())
          Result = L.udiv(R);
        break;
      case Instruction::Shl:
        if (R.ult(BW))
          Result = L.shl(R);
        break;
      case Instruction::LShr:
        if (R.ult(BW))
          Result = L.lshr(R);
        break;
      case Instruction::AShr:
        if (R.ult(BW))
          Result = L.ashr(R);
        break;
      case Instruction::And:
        Result = L & R;
        break;
      case Instruction::Or:
        Result = L | R;
        break;
      case Instruction::Xor:
        Result = L ^ R;
        break;
      default:
        break;
      }

      if (!Result)
        continue;

      BO->replaceAllUsesWith(ConstantInt::get(BO->getContext(), *Result));
      BO->eraseFromParent();
      Changed = true;
    }
  }

  return Changed;
}
